INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-8b44517b-moex-00317', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「當鑰匙在鎖孔轉動的喀嗒聲響起，這一天中所有疲倦、失意，就像鞋子上的灰塵一樣，都 留在門外了。那是一種風浪過後，船舶靠岸的感覺。是摘下面具、卸除防衛、還自家本來面 目的輕鬆。」 上文是某房屋經銷的廣告文案，下列何者最接近其訴求的重點？', '["大氣高雅", "清幽恬靜", "舒放自在", "精雕細琢"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00318', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「若視建築為凝聚意念而成的空間敘述，大都會相當於史詩或長篇，小鎮對應散文或短篇， 鄉村就是淺吟低唱的詩歌了。大城的高樓和下水道，以及窄巷死角貧民窟，說的是盛世繁華 大起大落。相對，小鎮簡單的街道和房屋，低訴趨近常人的小哀小樂。」 根據上文，下列何者最符合文意？', '["對比空間的情感意象", "控訴滄海桑田的無奈", "流連建築的歷史記憶", "批判城鄉差距的不公"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00319', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「夜深獨酌，從陽臺可見的觀音山，躺臥天地之間，時斜月輕掛，時星點醉灑。高粱再倒， 舉杯，竟彷彿邀山，邀月，也敬邀人間了。」 下列何者最能呼應上文的情感？', '["故人賞我趣，挈壺相與至", "遇酒且呵呵，人生能幾何", "晚來天欲雪，能飲一杯無", "舉杯邀明月，對影成三人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00320', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「世間微塵，歲華荏苒，有時我讀到『城中十萬戶，此地兩三家』而環顧四周，便有怡然的 滿足。眾生勞苦競走，像神農一樣遍嘗人間各毒，我猜那其實是生活殷憂的隱喻，在現代更 是如此。我到目前為止四方奔忙仍然一事無成，但我已不再如此憂戚，所謂『飄飄何所似， 天地一沙鷗』，靜夜掩卷，我對自己說，也許解毒的答案就在其中。」 根據上文，下列何者最接近作者的感悟？', '["風簷展書讀，古道照顏色", "萬般皆下品，唯有讀書高", "心寬天地闊，無憂歲月安", "吃得苦中苦，方為人上人"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00321', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「如此超高濃度、超大密度的相濡以沫，在網路興起之前，是不存在的。一個人說要入山閉 關，他大概就真的可以與世隔絕，缺月掛疏桐，靜聽松子落。現在，海外孤島、深山古剎也 有網路穿透，網路穿透之處，就是眾聲喧嘩之時。深山獨處，孤島離索，若是網路隨身，其 實就是行李中裝了重重罣礙，與滾滾紅塵一同上路了。何況所謂獨處，不在於身體是否單獨， 而在於心靈是否誠實地閉門，獨對內在。」 根據上文，下列何者最符合文意？', '["鼓勵現代人離群索居遠離網路提供的資訊", "疏桐影松子聲成為現代人無法接近的光景", "網路無遠弗屆造成現代人自我與人際混淆", "獨處的意義在於心靈能遠離喧囂面對自我"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00322', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '承上題，關於上文，作者認為網路的影響，下列何者錯誤？', '["網路帶來更繁複的人際關係", "網路眾聲喧嘩穿透生活界線", "現代人生活無法不靠著網路維持品質", "無所不在的網路使獨處變得更加困難"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00323', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「人類的所有餐飲食材中，有三分之一以上來自於由昆蟲授粉的植物，這一千多種作物中， 百分之八十以上需要蜜蜂幫忙傳播花粉。蜜蜂死了，很多花因為沒傳粉也死了，靠這些花的 果實為生的動物也死了。從蜜蜂的例子，我們可以知道，這些小小的昆蟲，對自然資源以及 其他生物造成多大的影響啊！一個生態系統的穩定度與它的複雜性有直接的關係。」 根據上文，下列何者最符合文意？', '["動輒得咎", "牽一髮而動全身", "失之毫釐，差之千里", "禍兮，福之所倚；福兮，禍之所伏"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00324', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「水資源產業是國民經濟發展基礎產業，優先發展與水資源相關的活動是一種必然的趨勢。 但發展中排放出大量的污水，也污染了水源，導致水資源功能下降，讓發展與污染產出兩者 更加的矛盾，給經濟環境帶來極大不利影響，嚴重地限制約束經濟社會的可持續發展。」 根據上文，下列何者最符合文意？', '["優先發展水資源產業，不利國民經濟發展", "限制水資源的利用，可有效改善經濟環境", "發展水資源產業的過程中，改善水源污染將導致水資源功能受限", "若能留意造成環境污染的社會成本，有助於經濟社會的持續發展"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00325', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「富人和窮人一樣受苦，因為外在的憂慮來自欲望。即使是億萬富翁也有憤怒、絕望、沮喪 的苦。他們很少享有真正的安寧與和平，只是憂慮現有的會失去或如何獲取現在所沒有的。 他們不能欣賞自己，活著只是為了那些吸引或奴役他們的東西。賺錢本身並不會產生痛苦， 但把自己的生命交給外在的財物，才是扼殺喜悅與安寧的劊子手。」 下列那一個選項最能說明本文的主旨？', '["財富不會產生痛苦", "欲望是痛苦的根源", "不論窮或富都會痛苦", "患得患失是痛苦的根源"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL),
  ('elementary-8b44517b-moex-00326', 'elementary-8b44517b', 'elementary-8b44517b-moex-113-34c7f7f6', 'sub-elementary-8b44517b-03', NULL, 'single_choice', '「透過正念飲食來練習恢復專注力，放慢用餐速度，讓吃飯成為一種『有意識』的行為。 當有意識地進食時，更能感受身體的飢餓和飽足程度，減緩暴飲暴食程度和避免情緒化的 飲食。」 根據上文，下列最符合正念飲食的理念是：', '["三餐定時定量，多吃蔬果，禁食垃圾食物", "用餐時，聊天或聽音樂可以放鬆緊張心情", "慢慢咀嚼每一口食物，並且感受食材滋味", "增強專注力，才可以有效節省用餐的時間"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:31+00:00", "source_pdf_sha1": "f3fed3528446", "answer_pdf_sha1": "c24fe4b6c105", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "503", "s": "0101", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "勞工行政"}'::jsonb, NULL)
